                 // if ( offset > io.size() ) offset = 0; // Denial of service?

                 // #55 memory allocation crash test/data/POC8
-                long long allocate = (long long) (size*count + pad+20);
-                if ( allocate > (long long) io.size() ) {
+                // Use 64-bit arithmetic to compute the total size required and
+                // validate against io.size() to avoid integer overflow.
+                uint64_t product64 = (uint64_t)size * (uint64_t)count;
+                uint64_t need64 = product64 + (uint64_t)pad + 20ULL;
+                if ( need64 > (uint64_t) io.size() ) {
                     throw Error(57);
