+                if ( need64 > (uint64_t) std::numeric_limits<long>::max() ) {
+                    // DataBuf takes a long; ensure we can represent the size safely
+                    throw Error(57);
+                }
+                long allocate = (long) need64;
+                DataBuf  buf(allocate);  // allocate a buffer
+                // Copy up to 4 bytes from dir into buf safely
+                if (allocate >= 4) std::memcpy(buf.pData_,dir.pData_+8,4);
+                else if (allocate > 0) std::memcpy(buf.pData_,dir.pData_+8,allocate);
+                const bool bOffsetIsPointer = product64 > 4;

                 if ( bOffsetIsPointer ) {         // read into buffer
+                    // Validate offset and requested read against io.size()
+                    uint64_t offset64 = (uint64_t)offset;
+                    if ( offset64 > (uint64_t) io.size() || offset64 + product64 > (uint64_t) io.size() ) {
+                        throw Error(57);
+                    }
+                    if ( offset64 > (uint64_t) std::numeric_limits<long>::max() ) {
+                        throw Error(57);
+                    }
                     size_t   restore = io.tell();  // save
-                    io.seek(offset,BasicIo::beg);  // position
-                    io.read(buf.pData_,count*size);// read
+                    io.seek((long)offset64,BasicIo::beg);  // position
+                    io.read(buf.pData_,(long)product64);// read
                     io.seek(restore,BasicIo::beg); // restore
                 }

