+	/* Compute row stride in a safe 64-bit manner to avoid integer overflow. */
+	{
+		uint64_t bits_per_row = 0ULL;
+		uint64_t row_bytes = 0ULL;
+		uint64_t padded_stride = 0ULL;
+		size_t alloc_size = 0ULL;
+
+		if (Info_h.biHeight == 0U) {
+			fprintf(stderr, "Error, invalid BMP height 0\n");
+			fclose(IN);
