+		if (Info_h.biBitCount == 4 && Info_h.biCompression == 2) { /* RLE4 decoded as 8 bits data */
+			bits_per_row = (uint64_t)Info_h.biWidth * 8ULL;
+		} else {
+			bits_per_row = (uint64_t)Info_h.biWidth * (uint64_t)Info_h.biBitCount;
