+		row_bytes = (bits_per_row + 7ULL) / 8ULL;
+		/* pad to 4-byte boundary as BMP rows are aligned on 32 bits */
+		padded_stride = ((row_bytes + 3ULL) / 4ULL) * 4ULL;
