--- a/libyara/compiler.c
+++ b/libyara/compiler.c
@@ -129,6 +129,26 @@ YR_API void yr_compiler_destroy(
   YR_FIXUP* fixup;
   int i;

+  /* Free file name stack first (allocated with yr_malloc) */
+  for (i = 0; i < compiler->file_name_stack_ptr; i++)
+    yr_free(compiler->file_name_stack[i]);
+
+  /*
+   * Free the fixup linked list before destroying arenas. Fixup entries
+   * may have been allocated with the general allocator (yr_malloc) and
+   * could reside in heap pages that are reused/freed by yr_arena_destroy.
+   * Destroying arenas before freeing the fixups can lead to a use-after-free
+   * when walking the fixup list (see CVE-2017-5924).
+   */
+  fixup = compiler->fixup_stack_head;
+
+  while (fixup != NULL)
+  {
+    YR_FIXUP* next_fixup = fixup->next;
+    yr_free(fixup);
+    fixup = next_fixup;
+  }
+
   yr_arena_destroy(compiler->compiled_rules_arena);
   yr_arena_destroy(compiler->sz_arena);
   yr_arena_destroy(compiler->rules_arena);
